SELECT ur.role_name, ot.type_name, UNICODE(ur.role_name) AS unicode_role_name, DEGREES(ot.observation_type_id) AS degree_observation_type_id
FROM users_roles ur
JOIN observation_types ot ON DEGREES(ot.observation_type_id) = UNICODE(ur.role_name);

SELECT ur.role_name
FROM users_roles ur
WHERE ur.role_name IN ('researcher', 'citizen scientist')
AND (
    SELECT COUNT(*) FROM (
        SELECT ot.observation_type_id
        FROM observation_types ot
        WHERE ot.type_name IN ('sighting', 'collection')
    ) obs
) < 500;

SELECT type_name, description
FROM observation_types
WHERE observation_type_id IN (0, 1);

SELECT role_name, permissions
FROM users_roles
WHERE role_id = 0;

SELECT *
FROM users_roles
CROSS JOIN observation_types;

SELECT ur.role_name, 'sighting' AS observation_type
FROM users_roles ur
WHERE ur.role_name = 'researcher' AND ur.permissions LIKE '%upload%';

SELECT role_name
FROM users_roles
WHERE permissions LIKE '%sighting%';

SELECT *
FROM users_roles
WHERE role_name = 'researcher';

SELECT type_name, COUNT(*) AS type_count
FROM observation_types
GROUP BY type_name;

SELECT * 
FROM users_roles 
JOIN observation_types;

SELECT role_name
FROM users_roles
WHERE permissions LIKE '%Can upload observations%';

SELECT users_roles.role_name, observation_types.type_name
FROM users_roles, observation_types
ORDER BY users_roles.role_name, observation_types.type_name;

SELECT ot.observation_type_id, ot.type_name, ot.description, ur.permissions
FROM observation_types ot
JOIN users_roles ur ON ot.type_name = ur.role_name;

SELECT type_name
   FROM observation_types
   WHERE description COLLATE NOCASE LIKE '%sighting%';

SELECT ur.role_name, ot.type_name
FROM users_roles ur, observation_types ot
WHERE ur.role_name = 'citizen scientist' AND ot.type_name = 'sighting';

SELECT type_name, description
FROM observation_types
WHERE observation_type_id = (
    SELECT MAX(observation_type_id)
    FROM observation_types
);

SELECT role_name
FROM users_roles
WHERE permissions LIKE '%upload%' AND permissions LIKE '%edit%';

SELECT type_name, COUNT(*) AS count
FROM observation_types
GROUP BY type_name;

SELECT role_name
FROM users_roles
WHERE permissions LIKE '%Can upload observations%';
